## Common patterns

### Checkbox group

Group related checkboxes together for multiple selections:

```jsx live-dev
const App = () => {
  const [selectedOptions, setSelectedOptions] = useState<string[]>([]);

  const options = [
    { id: 'option1', label: 'Email notifications' },
    { id: 'option2', label: 'SMS notifications' },
    { id: 'option3', label: 'Push notifications' },
  ];

  const handleToggle = (optionId: string) => {
    setSelectedOptions((prev) =>
      prev.includes(optionId)
        ? prev.filter((id) => id !== optionId)
        : [...prev, optionId]
    );
  };

  return (
    <Stack direction="column" gap="400">
      {options.map((option) => (
        <Checkbox
          key={option.id}
          isSelected={selectedOptions.includes(option.id)}
          onChange={() => handleToggle(option.id)}
        >
          {option.label}
        </Checkbox>
      ))}
      <Text fontSize="sm">
        Selected: {selectedOptions.length} of {options.length}
      </Text>
    </Stack>
  );
}
```

### Select all pattern

Implement a "select all" checkbox with indeterminate state:

```jsx live-dev
const App = () => {
  const [items, setItems] = useState([
    { id: '1', label: 'Item 1', selected: false },
    { id: '2', label: 'Item 2', selected: true },
    { id: '3', label: 'Item 3', selected: false },
  ]);

  const allSelected = items.every((item) => item.selected);
  const someSelected = items.some((item) => item.selected) && !allSelected;

  const handleSelectAll = (isSelected: boolean) => {
    setItems((prev) =>
      prev.map((item) => ({ ...item, selected: isSelected }))
    );
  };

  const handleToggleItem = (id: string) => {
    setItems((prev) =>
      prev.map((item) =>
        item.id === id ? { ...item, selected: !item.selected } : item
      )
    );
  };

  return (
    <Stack direction="column" gap="400">
      <Checkbox
        isSelected={allSelected}
        isIndeterminate={someSelected}
        onChange={handleSelectAll}
      >
        Select all
      </Checkbox>
      <Stack direction="column" gap="200" ml="600">
        {items.map((item) => (
          <Checkbox
            key={item.id}
            isSelected={item.selected}
            onChange={() => handleToggleItem(item.id)}
          >
            {item.label}
          </Checkbox>
        ))}
      </Stack>
    </Stack>
  );
}
```

### Form integration example

Integrate checkboxes with form state management:

```jsx live-dev
const App = () => {
  const [formData, setFormData] = useState({
    acceptTerms: false,
    subscribeNewsletter: false,
    shareData: false,
  });

  const handleChange = (field: string) => (isSelected: boolean) => {
    setFormData((prev) => ({ ...prev, [field]: isSelected }));
  };

  const handleSubmit = () => {
    if (!formData.acceptTerms) {
      alert('Please accept the terms and conditions');
      return;
    }
    alert('Form submitted!');
  };

  return (
    <Stack direction="column" gap="600">
      <Checkbox
        isSelected={formData.acceptTerms}
        onChange={handleChange('acceptTerms')}
        isInvalid={!formData.acceptTerms}
      >
        I accept the terms and conditions
      </Checkbox>
      <Checkbox
        isSelected={formData.subscribeNewsletter}
        onChange={handleChange('subscribeNewsletter')}
      >
        Subscribe to newsletter
      </Checkbox>
      <Checkbox
        isSelected={formData.shareData}
        onChange={handleChange('shareData')}
      >
        Allow data sharing for analytics
      </Checkbox>
      <Button onClick={handleSubmit}>Submit</Button>
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using Checkbox within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the component renders with expected elements

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Checkbox, NimbusProvider } from "@commercetools/nimbus";

describe("Checkbox - Basic rendering", () => {
  it("renders checkbox element", () => {
    render(
      <NimbusProvider>
        <Checkbox>Test checkbox</Checkbox>
      </NimbusProvider>
    );

    // Verify checkbox is present
    expect(screen.getByRole("checkbox")).toBeInTheDocument();
  });

  it("renders with label text", () => {
    render(
      <NimbusProvider>
        <Checkbox>Accept terms</Checkbox>
      </NimbusProvider>
    );

    expect(screen.getByText("Accept terms")).toBeInTheDocument();
  });

  it("renders with aria-label when no children provided", () => {
    render(
      <NimbusProvider>
        <Checkbox aria-label="Test checkbox" />
      </NimbusProvider>
    );

    expect(
      screen.getByRole("checkbox", { name: /test checkbox/i })
    ).toBeInTheDocument();
  });

  it("renders unchecked by default", () => {
    render(
      <NimbusProvider>
        <Checkbox>Unchecked checkbox</Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    expect(checkbox).not.toBeChecked();
  });
});
```

### Selection State Tests

Test different selection states (checked, unchecked, indeterminate)

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Checkbox, NimbusProvider } from "@commercetools/nimbus";

describe("Checkbox - Selection states", () => {
  it("renders checked state", () => {
    render(
      <NimbusProvider>
        <Checkbox isSelected>Checked checkbox</Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    expect(checkbox).toBeChecked();
  });

  it("renders indeterminate state", () => {
    render(
      <NimbusProvider>
        <Checkbox isIndeterminate>Indeterminate checkbox</Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    // React Aria sets indeterminate state on the input element, not aria-checked
    expect(checkbox).toHaveProperty("indeterminate", true);
  });

  it("renders unchecked state explicitly", () => {
    render(
      <NimbusProvider>
        <Checkbox isSelected={false}>Unchecked checkbox</Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    expect(checkbox).not.toBeChecked();
  });
});
```

### Interaction Tests

Test user interactions with the component

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Checkbox, NimbusProvider } from "@commercetools/nimbus";

describe("Checkbox - Interactions", () => {
  it("toggles when clicked", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <Checkbox>Toggle me</Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    expect(checkbox).not.toBeChecked();

    await user.click(checkbox);

    expect(checkbox).toBeChecked();
  });

  it("calls onChange callback when toggled", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <Checkbox onChange={handleChange}>Test checkbox</Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    await user.click(checkbox);

    expect(handleChange).toHaveBeenCalledWith(true);
  });

  it("toggles with spacebar when focused", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <Checkbox>Keyboard toggle</Checkbox>
      </NimbusProvider>
    );

    // Use userEvent.tab() instead of element.focus() to avoid act() warnings
    await user.tab();
    await user.keyboard(" ");

    expect(screen.getByRole("checkbox")).toBeChecked();
  });

  it("toggles with enter key when focused", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <Checkbox>Enter toggle</Checkbox>
      </NimbusProvider>
    );

    // Use userEvent.tab() instead of element.focus() to avoid act() warnings
    await user.tab();
    await user.keyboard("{Enter}");

    expect(screen.getByRole("checkbox")).toBeChecked();
  });
});
```

### Testing Controlled Mode

Test controlled component behavior

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Checkbox, NimbusProvider } from "@commercetools/nimbus";

describe("Checkbox - Controlled mode", () => {
  it("displays controlled value", () => {
    render(
      <NimbusProvider>
        <Checkbox isSelected={true} onChange={() => {}}>
          Controlled checkbox
        </Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    expect(checkbox).toBeChecked();
  });

  it("updates when controlled value changes", () => {
    const { rerender } = render(
      <NimbusProvider>
        <Checkbox isSelected={false} onChange={() => {}}>
          Controlled checkbox
        </Checkbox>
      </NimbusProvider>
    );

    expect(screen.getByRole("checkbox")).not.toBeChecked();

    rerender(
      <NimbusProvider>
        <Checkbox isSelected={true} onChange={() => {}}>
          Controlled checkbox
        </Checkbox>
      </NimbusProvider>
    );

    expect(screen.getByRole("checkbox")).toBeChecked();
  });

  it("calls onChange when user interacts with controlled checkbox", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <Checkbox isSelected={false} onChange={handleChange}>
          Controlled checkbox
        </Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    await user.click(checkbox);

    expect(handleChange).toHaveBeenCalledWith(true);
  });
});
```

### Testing Validation States

Test different validation and state variations

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Checkbox, NimbusProvider } from "@commercetools/nimbus";

describe("Checkbox - Validation states", () => {
  it("renders disabled state", () => {
    render(
      <NimbusProvider>
        <Checkbox isDisabled>Disabled checkbox</Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    expect(checkbox).toBeDisabled();
  });

  it("does not toggle when disabled", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <Checkbox isDisabled onChange={handleChange}>
          Disabled checkbox
        </Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    await user.click(checkbox);

    expect(checkbox).not.toBeChecked();
    expect(handleChange).not.toHaveBeenCalled();
  });

  it("renders invalid state", () => {
    render(
      <NimbusProvider>
        <Checkbox isInvalid>Invalid checkbox</Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    expect(checkbox).toHaveAttribute("aria-invalid", "true");
  });

  it("renders checked and disabled state", () => {
    render(
      <NimbusProvider>
        <Checkbox isSelected isDisabled>
          Checked and disabled
        </Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    expect(checkbox).toBeChecked();
    expect(checkbox).toBeDisabled();
  });

  it("renders indeterminate and invalid state", () => {
    render(
      <NimbusProvider>
        <Checkbox isIndeterminate isInvalid>
          Indeterminate and invalid
        </Checkbox>
      </NimbusProvider>
    );

    const checkbox = screen.getByRole("checkbox");
    // React Aria sets indeterminate state on the input element, not aria-checked
    expect(checkbox).toHaveProperty("indeterminate", true);
    expect(checkbox).toHaveAttribute("aria-invalid", "true");
  });
});
```


